let historico = [];
if (sessionRow?.historico) {
  if (typeof sessionRow.historico === 'string') { try { historico = JSON.parse(sessionRow.historico); } catch(e) {} }
  else if (Array.isArray(sessionRow.historico)) { historico = sessionRow.historico; }
}

const RUIDO = ['[object Object]', 'undefined', 'null', 'ERROR:'];
const historico_limpo = historico.filter(function(h) {
  return h && h.role && typeof h.content === 'string' && h.content.trim() !== '' &&
         (h.role === 'user' || h.role === 'assistant') &&
         !RUIDO.some(function(p) { return h.content.includes(p); });
});

// TRAVA DE SEGURANÇA INFINITA: Mais de 5 msgs em menos de 2 mins
const agora = Date.now();
const msgsRecentes = historico_limpo.filter(h => h.ts && (agora - h.ts) < 120000);
if (msgsRecentes.length >= 5) {
  // O usuário está numa rajada intensa ou é um bot respondendo na hora. 
  // Silencia para evitar consumo de API.
  return [];
}

const assistantCount = historico_limpo.filter(function(h) { return h.role === 'assistant'; }).length;
const msgLower = message.toLowerCase();
