const isSim = ['sim', 'quero', 'pode', 'bora', 'com certeza', 'ok', 'manda', 'interessa', 'faz'].some(function(w) { return msgLower.includes(w); });
const isColeta = msgLower.includes('@') || msgLower.includes('empresa') || msgLower.includes('.com');

const aceitesCount = historico_limpo.filter(function(h) {
    if (h.role !== 'user') return false;
    const l = h.content.toLowerCase();
    return ['sim', 'quero', 'pode', 'bora', 'com certeza', 'ok', 'manda', 'interessa', 'faz'].some(function(w) { return l.includes(w); });
}).length;

let stage = 'APRESENTACAO';

// REGRA ALEX 9.1 (Trava de Rajada e Anti-Loop)
if (assistantCount === 0) {
    stage = 'APRESENTACAO';
} else if (assistantCount >= 1 && assistantCount <= 2) {
    if (isNao) stage = 'OBJECAO';
    else stage = 'DOUTRINACAO';
} else if (assistantCount === 3) {
    if (isNao) stage = 'OBJECAO';
    else stage = 'FECHAMENTO';
} else {
    if (isNao) {
        stage = 'OBJECAO';
    } else {
        if (isSim && aceitesCount > 1 || isColeta) {
            stage = 'ENTREGA_PDF';
        } else {
            stage = 'COLETA';
        }
    }
}

