// Fallback final
if (!textoLimpo) {
  textoLimpo = 'Entendido, vou verificar isso para você.';
}

return [{ json: {
  isEncerrado: false, // Sempre falso no modo copiloto
  textoLimpo: textoLimpo,
  phone: phone
